import numpy as np

def detect_barren_plateau(grad_fn, n_params, n_samples=50):
    grads = []
    for _ in range(n_samples):
        p = np.random.uniform(-np.pi, np.pi, n_params)
        grads.append(grad_fn(p))
    var = np.var(grads, axis=0)
    return {'variance': np.mean(var), 'is_barren': np.mean(var) < 1e-6}

def fake_grad(p): return np.random.randn(len(p)) * 1e-8
result = detect_barren_plateau(fake_grad, 5)
print(result)

import numpy as np

def identity_init(n_params, eps=0.01):
    return eps * np.random.randn(n_params)

params = identity_init(10)
print(f"Mean: {np.mean(np.abs(params)):.4f}")
print(f"Max: {np.max(np.abs(params)):.4f}")
